export declare const editorStyles = "\n  .ProseMirror {\n    min-height: 200px;\n  }\n  \n  .ProseMirror > * + * {\n    margin-top: 0.75em;\n  }\n\n  .ProseMirror h1 {\n    font-size: 2.5rem;\n    font-weight: 700;\n    line-height: 1.2;\n    margin-bottom: 0.5em;\n    color: var(--color-primary-text);\n  }\n\n  .ProseMirror h2 {\n    font-size: 1.875rem;\n    font-weight: 600;\n    line-height: 1.3;\n    margin-top: 1.5em;\n    color: var(--color-primary-text);\n  }\n\n  .ProseMirror h3 {\n    font-size: 1.5rem;\n    font-weight: 600;\n    line-height: 1.4;\n    margin-top: 1.5em;\n    color: var(--color-primary-text);\n  }\n\n  .ProseMirror p {\n    font-size: 1rem;\n    line-height: 1.75;\n    color: var(--color-secondary-text);\n  }\n\n  .ProseMirror ul,\n  .ProseMirror ol {\n    padding-left: 1.5rem;\n    color: var(--color-secondary-text);\n  }\n\n  .ProseMirror ul li {\n    list-style-type: disc;\n    padding-left: 0.25rem;\n  }\n\n  .ProseMirror ol li {\n    list-style-type: decimal;\n    padding-left: 0.25rem;\n  }\n\n  .ProseMirror li {\n    margin-top: 0.5em;\n    line-height: 1.75;\n  }\n\n  .ProseMirror blockquote {\n    border-left: 2px solid var(--color-stroke);\n    padding-left: 1rem;\n    font-style: italic;\n    color: var(--color-primary-text);\n    margin: 1.5em 0;\n  }\n\n  .ProseMirror code {\n    color: var(--color-secondary-text);\n    padding: 0.2em 0.4em;\n    border-radius: 0.25rem;\n    font-size: 0.875em;\n  }\n\n  .ProseMirror pre {\n    background-color: rgba(31, 41, 55, 0.3);\n    color: var(--color-secondary-text);\n    padding: 1rem;\n    border-radius: 0.5rem;\n    overflow-x: auto;\n    \n    font-size: 0.875rem;\n    line-height: 1.5;\n    margin: 1.5em 0;\n  }\n\n  .ProseMirror pre code {\n    background: none;\n    color: inherit;\n    padding: 0;\n    font-size: inherit;\n  }\n\n  .ProseMirror hr {\n    border: none;\n    border-top: 2px solid var(--color-border);\n    margin: 2rem 0;\n  }\n\n  .ProseMirror img {\n    max-width: 100%;\n    height: auto;\n    border-radius: 0.5rem;\n    margin: 1em 0;\n  }\n\n  .ProseMirror img[style*=\"text-align: center\"] {\n    display: block;\n    margin-left: auto;\n    margin-right: auto;\n  }\n\n  .ProseMirror img[style*=\"text-align: right\"] {\n    display: block;\n    margin-left: auto;\n    margin-right: 0;\n  }\n\n  .ProseMirror mark {\n    background-color: #fef3c7;\n    padding: 0.125em 0.25em;\n    border-radius: 0.125rem;\n  }\n\n  .ProseMirror p.is-editor-empty:first-child::before {\n    color: var(--disabled-text);\n    content: attr(data-placeholder);\n    float: left;\n    height: 0;\n    pointer-events: none;\n  }\n\n  .ProseMirror h1.is-empty::before,\n  .ProseMirror h2.is-empty::before,\n  .ProseMirror h3.is-empty::before {\n    color: #adb5bd;\n    content: attr(data-placeholder);\n    float: left;\n    height: 0;\n    pointer-events: none;\n  }\n\n  .ProseMirror:focus {\n    outline: none;\n  }\n\n  .ProseMirror a {\n    color: #3b82f6;\n    text-decoration: underline;\n    cursor: pointer;\n  }\n\n  .ProseMirror a:hover {\n    color: #2563eb;\n  }\n    \n.prose h1 a,\n.prose h2 a,\n.prose h3 a,\n.prose h4 a,\n.prose h5 a,\n.prose h6 a {\n  color: inherit !important;\n  text-decoration: none !important;\n  font-weight: inherit !important;\n}\n  ";
